Exit fullscreen mode

以下を生成：

-- Exported from HTML Table Exporter PRO
CREATE TABLE products (
product_name TEXT,
price REAL,
in_stock TEXT
);
INSERT INTO products (product_name, price, in_stock) VALUES
('Widget Pro', 29.99, 'Yes'),
('Gadget Basic', 14.50, 'No');

